// BankingServiceImpl.java
package com.banking.ws.service;

import com.banking.ws.model.BankingTransaction;
import com.banking.ws.model.TransactionRequest;
import com.banking.ws.model.TransactionResponse;

import javax.jws.WebService;
import javax.xml.ws.BindingType;
import java.math.BigDecimal;
import java.util.Date;
import java.util.HashMap;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

@WebService(
        serviceName = "BankingService",
        portName = "BankingServicePort",
        targetNamespace = "http://banking.com/ws",
        endpointInterface = "com.banking.ws.service.BankingService"
)
@BindingType(value = javax.xml.ws.soap.SOAPBinding.SOAP11HTTP_BINDING)
public class BankingServiceImpl implements BankingService {

    private static final Map<String, BankingTransaction> transactions = new ConcurrentHashMap<>();
    private static final Map<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();

    static {
        accountBalances.put("ACC001", new BigDecimal("10000.00"));
        accountBalances.put("ACC002", new BigDecimal("5000.00"));
        accountBalances.put("ACC003", new BigDecimal("15000.00"));
    }

    @Override
    public TransactionResponse processTransaction(TransactionRequest request) {
        try {
            if (request == null || request.getFromAccount() == null || request.getToAccount() == null) {
                return new TransactionResponse(false, null, "Invalid request", "ERR_INVALID_REQUEST");
            }

            if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
                return new TransactionResponse(false, null, "Invalid amount", "ERR_INVALID_AMOUNT");
            }

            BigDecimal fromBalance = accountBalances.get(request.getFromAccount());
            if (fromBalance == null) {
                return new TransactionResponse(false, null, "Source account not found", "ERR_ACCOUNT_NOT_FOUND");
            }

            if (fromBalance.compareTo(request.getAmount()) < 0) {
                return new TransactionResponse(false, null, "Insufficient funds", "ERR_INSUFFICIENT_FUNDS");
            }

            BigDecimal toBalance = accountBalances.get(request.getToAccount());
            if (toBalance == null) {
                return new TransactionResponse(false, null, "Destination account not found", "ERR_ACCOUNT_NOT_FOUND");
            }

            String transactionId = UUID.randomUUID().toString();

            accountBalances.put(request.getFromAccount(), fromBalance.subtract(request.getAmount()));
            accountBalances.put(request.getToAccount(), toBalance.add(request.getAmount()));

            BankingTransaction transaction = new BankingTransaction(
                    transactionId,
                    request.getFromAccount(),
                    request.getToAccount(),
                    request.getAmount(),
                    request.getCurrency() != null ? request.getCurrency() : "USD",
                    new Date(),
                    "COMPLETED",
                    request.getDescription()
            );

            transactions.put(transactionId, transaction);

            return new TransactionResponse(true, transactionId, "Transaction completed successfully", null);

        } catch (Exception e) {
            return new TransactionResponse(false, null, "Transaction failed: " + e.getMessage(), "ERR_INTERNAL_ERROR");
        }
    }

    @Override
    public BankingTransaction getTransactionStatus(String transactionId) {
        return transactions.get(transactionId);
    }

    @Override
    public String getAccountBalance(String accountNumber) {
        BigDecimal balance = accountBalances.get(accountNumber);
        if (balance == null) {
            return "Account not found";
        }
        return balance.toString();
    }
}

