package com.banking.ws.security;

import org.apache.wss4j.common.ext.WSPasswordCallback;

import javax.security.auth.callback.Callback;
import javax.security.auth.callback.CallbackHandler;
import javax.security.auth.callback.UnsupportedCallbackException;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

public class SecurityCallbackHandler implements CallbackHandler {

    private static final Map<String, String> passwords = new HashMap<>();

    static {
        passwords.put("bankingclient", "clientpass123");
        passwords.put("bankingserver", "serverpass123");
    }

    @Override
    public void handle(Callback[] callbacks) throws IOException, UnsupportedCallbackException {
        for (Callback callback : callbacks) {
            if (callback instanceof WSPasswordCallback) {
                WSPasswordCallback pc = (WSPasswordCallback) callback;
                String password = passwords.get(pc.getIdentifier());
                if (password != null) {
                    pc.setPassword(password);
                } else {
                    throw new IOException("Unknown identifier: " + pc.getIdentifier());
                }
            } else {
                throw new UnsupportedCallbackException(callback, "Unrecognized Callback");
            }
        }
    }
}

// SignatureVerificationInterceptor.java
package com.banking.ws.security;

import org.apache.cxf.binding.soap.SoapMessage;
import org.apache.cxf.binding.soap.interceptor.AbstractSoapInterceptor;
import org.apache.cxf.interceptor.Fault;
import org.apache.cxf.phase.Phase;
import org.apache.wss4j.dom.WSConstants;
import org.apache.wss4j.dom.engine.WSSecurityEngine;
import org.apache.wss4j.dom.engine.WSSecurityEngineResult;
import org.apache.wss4j.dom.handler.RequestData;
import org.apache.wss4j.dom.handler.WSHandlerResult;
import org.w3c.dom.Document;

import javax.xml.soap.SOAPMessage;
import java.util.List;
import java.util.logging.Logger;

public class SignatureVerificationInterceptor extends AbstractSoapInterceptor {

    private static final Logger logger = Logger.getLogger(SignatureVerificationInterceptor.class.getName());

    public SignatureVerificationInterceptor() {
        super(Phase.PRE_PROTOCOL);
    }

    @Override
    public void handleMessage(SoapMessage message) throws Fault {
        try {
            SOAPMessage soapMessage = message.getContent(SOAPMessage.class);
            if (soapMessage == null) {
                return;
            }

            Document doc = soapMessage.getSOAPPart();

            WSSecurityEngine securityEngine = new WSSecurityEngine();
            RequestData reqData = new RequestData();
            reqData.setCallbackHandler(new SecurityCallbackHandler());

            List<WSSecurityEngineResult> results = securityEngine.processSecurityHeader(doc, reqData);

            boolean signatureFound = false;
            if (results != null) {
                for (WSSecurityEngineResult result : results) {
                    Integer action = (Integer) result.get(WSSecurityEngineResult.TAG_ACTION);
                    if (action != null && action.equals(WSConstants.SIGN)) {
                        signatureFound = true;
                        logger.info("Signature verified successfully");
                        break;
                    }
                }
            }

            if (signatureFound) {
                logger.info("Message signature verification completed");
            }

        } catch (Exception e) {
            logger.severe("Signature verification failed: " + e.getMessage());
            throw new Fault(new Exception("Signature verification failed: " + e.getMessage()));
        }
    }
}

// SOAPMessageParser.java
package com.banking.ws.security;

import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathFactory;
import java.io.ByteArrayInputStream;
import java.util.HashMap;
import java.util.Map;

public class SOAPMessageParser {

    public static Map<String, String> extractSignedElements(String soapMessage) throws Exception {
        Map<String, String> signedElements = new HashMap<>();

        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(new ByteArrayInputStream(soapMessage.getBytes()));

        XPathFactory xPathFactory = XPathFactory.newInstance();
        XPath xpath = xPathFactory.newXPath();

        NodeList signatureNodes = (NodeList) xpath.evaluate(
                "//*[local-name()='Signature']",
                doc,
                XPathConstants.NODESET
        );

        if (signatureNodes.getLength() > 0) {
            Element signatureElement = (Element) signatureNodes.item(0);
            NodeList signedInfoNodes = signatureElement.getElementsByTagNameNS(
                    "http://www.w3.org/2000/09/xmldsig#",
                    "SignedInfo"
            );

            if (signedInfoNodes.getLength() > 0) {
                Element signedInfo = (Element) signedInfoNodes.item(0);
                NodeList referenceNodes = signedInfo.getElementsByTagNameNS(
                        "http://www.w3.org/2000/09/xmldsig#",
                        "Reference"
                );

                for (int i = 0; i < referenceNodes.getLength(); i++) {
                    Element reference = (Element) referenceNodes.item(i);
                    String uri = reference.getAttribute("URI");
                    if (uri != null && uri.startsWith("#")) {
                        String id = uri.substring(1);
                        NodeList elements = (NodeList) xpath.evaluate(
                                "//*[@*[local-name()='Id']='" + id + "']",
                                doc,
                                XPathConstants.NODESET
                        );
                        if (elements.getLength() > 0) {
                            Element signedElement = (Element) elements.item(0);
                            signedElements.put(id, getElementContent(signedElement));
                        }
                    }
                }
            }
        }

        return signedElements;
    }

    private static String getElementContent(Element element) {
        StringBuilder content = new StringBuilder();
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.TEXT_NODE) {
                content.append(child.getNodeValue());
            } else if (child.getNodeType() == Node.ELEMENT_NODE) {
                content.append(child.getNodeName()).append(": ");
                content.append(getElementContent((Element) child));
            }
        }
        return content.toString();
    }

    public static String extractBodyContent(String soapMessage) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(new ByteArrayInputStream(soapMessage.getBytes()));

        XPathFactory xPathFactory = XPathFactory.newInstance();
        XPath xpath = xPathFactory.newXPath();

        NodeList bodyNodes = (NodeList) xpath.evaluate(
                "//*[local-name()='Body']",
                doc,
                XPathConstants.NODESET
        );

        if (bodyNodes.getLength() > 0) {
            Element body = (Element) bodyNodes.item(0);
            return getElementContent(body);
        }

        return "";
    }
}

