import org.apache.cxf.Bus;
import org.apache.cxf.bus.spring.SpringBus;
import org.apache.cxf.jaxws.EndpointImpl;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.dom.handler.WSHandlerConstants;

import javax.xml.ws.Endpoint;
import java.util.HashMap;
import java.util.Map;

public class BankingServicePublisher {

    public static void main(String[] args) {
        String address = "http://localhost:8080/banking/services/BankingService";

        Bus bus = new SpringBus();
        EndpointImpl endpoint = new EndpointImpl(bus, new BankingServiceImpl());

        Map<String, Object> inProps = new HashMap<>();
        inProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        inProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        inProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, SecurityCallbackHandler.class.getName());

        WSS4JInInterceptor wss4jIn = new WSS4JInInterceptor(inProps);
        endpoint.getInInterceptors().add(wss4jIn);

        Map<String, Object> outProps = new HashMap<>();
        outProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        outProps.put(WSHandlerConstants.USER, "bankingserver");
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "server-crypto.properties");
        outProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, SecurityCallbackHandler.class.getName());

        WSS4JOutInterceptor wss4jOut = new WSS4JOutInterceptor(outProps);
        endpoint.getOutInterceptors().add(wss4jOut);

        endpoint.publish(address);

        System.out.println("Banking Service published at: " + address);
    }
}

