import com.banking.ws.service.BankingService;
import org.apache.cxf.endpoint.Client;
import org.apache.cxf.frontend.ClientProxy;
import org.apache.cxf.jaxws.JaxWsProxyFactoryBean;
import org.apache.cxf.ws.security.wss4j.WSS4JInInterceptor;
import org.apache.cxf.ws.security.wss4j.WSS4JOutInterceptor;
import org.apache.wss4j.dom.handler.WSHandlerConstants;

import java.math.BigDecimal;
import java.util.HashMap;
import java.util.Map;

public class BankingServiceClient {

    public static void main(String[] args) {
        String serviceUrl = "http://localhost:8080/banking/services/BankingService";

        JaxWsProxyFactoryBean factory = new JaxWsProxyFactoryBean();
        factory.setServiceClass(BankingService.class);
        factory.setAddress(serviceUrl);

        Map<String, Object> outProps = new HashMap<>();
        outProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        outProps.put(WSHandlerConstants.USER, "bankingclient");
        outProps.put(WSHandlerConstants.SIG_PROP_FILE, "client-crypto.properties");
        outProps.put(WSHandlerConstants.PW_CALLBACK_CLASS, SecurityCallbackHandler.class.getName());

        WSS4JOutInterceptor wss4jOut = new WSS4JOutInterceptor(outProps);
        factory.getOutInterceptors().add(wss4jOut);

        Map<String, Object> inProps = new HashMap<>();
        inProps.put(WSHandlerConstants.ACTION, WSHandlerConstants.SIGNATURE);
        inProps.put(WSHandlerConstants.SIG_PROP_FILE, "client-crypto.properties");

        WSS4JInInterceptor wss4jIn = new WSS4JInInterceptor(inProps);
        factory.getInInterceptors().add(wss4jIn);

        BankingService service = (BankingService) factory.create();

        TransactionRequest request = new TransactionRequest(
                "ACC001",
                "ACC002",
                new BigDecimal("100.00"),
                "USD",
                "Transfer funds"
        );

        TransactionResponse response = service.processTransaction(request);

        System.out.println("Transaction Success: " + response.isSuccess());
        System.out.println("Transaction ID: " + response.getTransactionId());
        System.out.println("Message: " + response.getMessage());

        String balance = service.getAccountBalance("ACC001");
        System.out.println("Account Balance: " + balance);
    }
}